import java.util.*;

 class Road {
  int u, v, capacity;

  Road(int u, int v, int capacity) {
  this.u = u;
  this.v = v;
  this.capacity = capacity;
  }
 }

 public class MaxVehiclesRoadNetwork {
  static int[] parent;

  static int find(int x) {
  if (parent[x] != x)
  parent[x] = find(parent[x]);
  return parent[x];
  }

  static boolean union(int x, int y) {
  int px = find(x), py = find(y);
  if (px == py) return false;
  parent[px] = py;
  return true;
  }

  public static int maxVehicles(int n, List<Road> roads) {
  parent = new int[n];
  for (int i = 0; i < n; i++) parent[i] = i;


  roads.sort((a, b) -> Integer.compare(b.capacity, a.capacity));

  int totalCapacity = 0;
  int edgesUsed = 0;

  for (Road road : roads) {
  if (union(road.u, road.v)) {
  totalCapacity += road.capacity;
  edgesUsed++;
  if (edgesUsed == n - 1) break;
  }
  }

  return (edgesUsed == n - 1) ? totalCapacity : -1;
  }

  public static void main(String[] args) {
  Scanner sc = new Scanner(System.in);

  int e = sc.nextInt(); 
  List<Road> roads = new ArrayList<>();
  int maxNode = 0;

  for (int i = 0; i < e; i++) {
  int a = sc.nextInt();
  int b = sc.nextInt();
  int c = sc.nextInt();

  roads.add(new Road(a-1, b-1, c));
  maxNode = Math.max(maxNode, Math.max(a-1, b-1));
  }

  int n = maxNode + 1; 

  int result = maxVehicles(n, roads);
  if (result != -1)
  System.out.println("Maximum total vehicle capacity: " + result);
  else
  System.out.println("Not enough roads to connect all cities.");
  }
  sc.close();
 }

