import java.util.*;

 class Graph{
  int c=0;
  int bfs(int n, ArrayList<ArrayList<Integer>> adj,int st,int k){
  boolean vis[]=new boolean[n+1];
  Queue<Integer> q=new LinkedList<>();
  q.add(st);
  vis[st]=true;
  while(!q.isEmpty() && k>=0){
  int s=q.size();

  for(int i=0;i<s;i++){
  int a=q.poll();
  c++;
  for(int it:adj.get(a)){
  if(!vis[it]){
  vis[it]=true;
  q.add(it);
  }
  }
  }
  k--;
  }
  return c;
  }
 }
